#!/usr/bin/env python3
"""Slough trace animation  -  generated by slough dry-run library."""
import time
import turtle
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any


@dataclass(frozen=True)
class AnimationConfig:
    delay: float = 0.8
    font: tuple = ('Consolas', 10, 'normal')
    font_bold: tuple = ('Consolas', 11, 'bold')
    font_small: tuple = ('Consolas', 8, 'normal')
    bg: str = '#ffffff'
    code_bg: str = '#f5f5f5'
    var_bg: str = '#fafafa'
    highlight_bg: str = '#e8f0fe'
    highlight_fg: str = '#1a1a1a'
    text_color: str = '#000000'
    line_num_color: str = '#888888'
    key_color: str = '#1a56db'
    val_color: str = '#16a34a'
    box_color: str = '#d4d4d4'
    accent: str = '#7c3aed'
    fail_color: str = '#dc2626'
    ds_bg: str = '#f0f0f0'
    screen_width: int = 1400
    screen_height: int = 900
    title: str = 'Slough Dry-Run Animation'
    panel_width: int = 660
    panel_height: int = 770
    panel_top: int = 380
    code_panel_x: int = -680
    var_panel_x: int = 10
    header_width: int = 1360
    header_height: int = 40
    header_y: int = 400
    code_line_h: int = 20
    code_visible: int = 35
    code_start_y: int = 310
    var_line_h: int = 18
    var_start_y: int = 280
    var_max_val_len: int = 80
    var_key_x: int = 20
    var_val_x: int = 140
    ds_start_x: int = 40
    list_box_w: int = 48
    list_box_h: int = 28
    list_gap: int = 4
    list_pad: int = 8

class TurtleRenderer:
    """Facade over turtle.Turtle providing high-level drawing operations."""

    def __init__(self, config: AnimationConfig) -> None:
        self._config = config
        self._screen = turtle.Screen()
        self._turtle = turtle.Turtle()
        self._setup()

    def _setup(self) -> None:
        cfg = self._config
        self._screen.setup(cfg.screen_width, cfg.screen_height)
        self._screen.bgcolor(cfg.bg)
        self._screen.tracer(0)
        self._screen.title(cfg.title)
        self._screen.cv._rootwindow.resizable(False, False)
        self._turtle.speed(0)
        self._turtle.hideturtle()

    def draw_rect(self, x: float, y: float, w: float, h: float, color: str) -> None:
        t = self._turtle
        t.penup()
        t.goto(x, y)
        t.pendown()
        t.fillcolor(color)
        t.pencolor(color)
        t.begin_fill()
        for _ in range(2):
            t.forward(w)
            t.right(90)
            t.forward(h)
            t.right(90)
        t.end_fill()

    def write_text(self, x: float, y: float, text: str, font: tuple | None=None, color: str | None=None, align: str='left') -> None:
        t = self._turtle
        t.penup()
        t.goto(x, y)
        t.pencolor(color or self._config.text_color)
        t.write(text, font=font or self._config.font, align=align)

    def draw_arrow(self, x1: float, y1: float, x2: float, y2: float) -> None:
        t = self._turtle
        t.penup()
        t.goto(x1, y1)
        t.pendown()
        t.pencolor(self._config.accent)
        t.pensize(2)
        t.goto(x2, y2)
        t.pensize(1)

    def update(self) -> None:
        self._screen.update()

    def exit_on_click(self) -> None:
        self._screen.exitonclick()

class DataStructureVisualizer(ABC):
    """Abstract strategy for rendering a data structure."""

    @abstractmethod
    def can_visualize(self, value: Any) -> bool:
        ...

    @abstractmethod
    def draw(self, renderer: TurtleRenderer, config: AnimationConfig, value: Any, y_start: float) -> tuple[bool, float]:
        ...

class ListVisualizer(DataStructureVisualizer):
    """Renders flat sequences as index boxes."""

    def can_visualize(self, value: Any) -> bool:
        return isinstance(value, list | tuple) and 2 <= len(value) <= 20 and all(not isinstance(v, list | dict) for v in value)

    def draw(self, renderer: TurtleRenderer, config: AnimationConfig, value: Any, y_start: float) -> tuple[bool, float]:
        items = list(value)
        box_w = config.list_box_w
        box_h = config.list_box_h
        gap = config.list_gap
        total_w = len(items) * (box_w + gap)
        start_x = config.ds_start_x
        if total_w > 620:
            box_w = max(20, 620 // len(items) - gap)
            total_w = len(items) * (box_w + gap)
        bg_y = y_start + config.list_pad // 2
        renderer.draw_rect(start_x - config.list_pad // 2, bg_y, total_w + config.list_pad, box_h + config.list_pad, config.ds_bg)
        for i, val in enumerate(items):
            bx = start_x + i * (box_w + gap)
            renderer.draw_rect(bx, y_start, box_w, box_h, config.box_color)
            label = str(val) if len(str(val)) < 6 else str(val)[:5]
            renderer.write_text(bx + box_w / 2, y_start + box_h / 2 - 5, label, config.font_small, config.text_color, 'center')
            renderer.write_text(bx + box_w / 2, y_start - 14, str(i), ('Consolas', 7, 'normal'), config.line_num_color, 'center')
        return (True, y_start - box_h - 30)

class DictVisualizer(DataStructureVisualizer):
    """Renders dictionaries as key -> value pairs."""

    def can_visualize(self, value: Any) -> bool:
        return isinstance(value, dict) and bool(value)

    def draw(self, renderer: TurtleRenderer, config: AnimationConfig, value: Any, y_start: float) -> tuple[bool, float]:
        line_h = 16
        count = 0
        for k, v in value.items():
            if y_start - count * line_h < -360:
                break
            label = f'{k!r}  ->  {v!r}'
            if len(label) > 70:
                label = label[:67] + '...'
            renderer.write_text(config.ds_start_x, y_start - count * line_h, label, ('Consolas', 9, 'normal'), config.key_color)
            count += 1
        return (count > 0, y_start - count * line_h - 10)

class TreeVisualizer(DataStructureVisualizer):
    """Renders linked lists (duck-typed via .val / .next attributes)."""

    def can_visualize(self, value: Any) -> bool:
        return hasattr(value, 'val')

    def draw(self, renderer: TurtleRenderer, config: AnimationConfig, value: Any, y_start: float) -> tuple[bool, float]:
        node = value
        h = self._node_height(node)
        if h > 8:
            renderer.write_text(config.ds_start_x, y_start, f'Tree ({h} levels) - too large to render', config.font, config.line_num_color)
            return (True, y_start - 20)
        if self._is_linked_list(node):
            return self._draw_linked_list(renderer, config, node, y_start)
        return (False, y_start)

    @staticmethod
    def _node_height(n: Any, visited: set[int] | None=None) -> int:
        if visited is None:
            visited = set()
        if n is None or id(n) in visited:
            return 0
        visited.add(id(n))
        h = 1
        for attr in ('next', 'left', 'right'):
            child = getattr(n, attr, None)
            if child is not None:
                h = max(h, 1 + TreeVisualizer._node_height(child, visited))
        return h

    @staticmethod
    def _is_linked_list(n: Any) -> bool:
        return hasattr(n, 'next') and (not (hasattr(n, 'left') or hasattr(n, 'right')))

    def _draw_linked_list(self, renderer: TurtleRenderer, config: AnimationConfig, node: Any, y_start: float) -> tuple[bool, float]:
        visited: set[int] = set()
        x = config.ds_start_x
        y = y_start
        node_w = 44
        node_h = 28
        gap = 10
        current = node
        while current is not None and id(current) not in visited:
            visited.add(id(current))
            renderer.draw_rect(x, y, node_w, node_h, config.box_color)
            label = str(current.val) if len(str(current.val)) < 5 else str(current.val)[:4]
            renderer.write_text(x + node_w / 2, y + node_h / 2 - 5, label, config.font_small, config.text_color, 'center')
            next_node = getattr(current, 'next', None)
            if next_node is not None:
                ax = x + node_w + 2
                ay = y + node_h / 2
                renderer.draw_arrow(ax, ay, ax + 6, ay)
            x += node_w + gap
            if x > 640:
                renderer.write_text(x, y, '...', config.font, config.line_num_color)
                break
            current = next_node
        return (True, y - 20 - node_h)

class VisualizerFactory:
    """Selects the appropriate data structure visualizer for a value."""

    def __init__(self) -> None:
        self._visualizers: list[DataStructureVisualizer] = [ListVisualizer(), DictVisualizer(), TreeVisualizer()]

    def draw(self, renderer: TurtleRenderer, config: AnimationConfig, value: Any, y_start: float) -> tuple[bool, float]:
        for viz in self._visualizers:
            if viz.can_visualize(value):
                return viz.draw(renderer, config, value, y_start)
        return (False, y_start)

class Panel(ABC):
    """Base class for a renderable screen panel."""

    def __init__(self, config: AnimationConfig) -> None:
        self._config = config

    @abstractmethod
    def draw(self, renderer: TurtleRenderer, **kwargs: Any) -> None:
        ...

class CodePanel(Panel):
    """Renders source code with current line highlighted."""

    def draw(self, renderer: TurtleRenderer, source_lines: list[str], highlight_lineno: int | None=None) -> None:
        cfg = self._config
        renderer.draw_rect(cfg.code_panel_x, cfg.panel_top, cfg.panel_width, cfg.panel_height, cfg.code_bg)
        renderer.write_text(cfg.code_panel_x + 10, cfg.panel_top - 25, ' Source', cfg.font_bold, cfg.accent)
        renderer.write_text(cfg.code_panel_x + 10, cfg.panel_top - 40, ' Code', cfg.font_bold, cfg.accent)
        line_h = cfg.code_line_h
        visible = cfg.code_visible
        start_line = max(0, (highlight_lineno or 1) - visible // 2)
        end_line = min(len(source_lines), start_line + visible)
        lineno_x = cfg.code_panel_x + 10
        text_x = cfg.code_panel_x + 40
        for i in range(start_line, end_line):
            lineno = i + 1
            y = cfg.code_start_y - (i - start_line) * line_h
            raw = source_lines[i].rstrip('\\n').rstrip('\\r')
            if highlight_lineno == lineno:
                renderer.draw_rect(cfg.code_panel_x + 2, y - 4, cfg.panel_width - 4, line_h, cfg.highlight_bg)
                renderer.write_text(lineno_x, y - line_h + 16, f'{lineno:>3}', cfg.font_small, cfg.line_num_color)
                renderer.write_text(text_x, y - line_h + 16, raw, cfg.font, cfg.text_color)
                renderer.write_text(text_x, y - line_h + 16, raw, ('Consolas', 10, 'bold'), cfg.highlight_fg)
            else:
                renderer.write_text(lineno_x, y - line_h + 16, f'{lineno:>3}', cfg.font_small, cfg.line_num_color)
                renderer.write_text(text_x, y - line_h + 16, raw, cfg.font, cfg.text_color)

class VariablesPanel(Panel):
    """Renders variable state for the current trace step."""

    def __init__(self, config: AnimationConfig) -> None:
        super().__init__(config)
        self._viz_factory = VisualizerFactory()

    def draw(self, renderer: TurtleRenderer, vars_dict: dict[str, Any], step_idx: int, total_steps: int, event: str, func_name: str, return_value: Any | None=None) -> None:
        cfg = self._config
        renderer.draw_rect(cfg.var_panel_x, cfg.panel_top, cfg.panel_width, cfg.panel_height, cfg.var_bg)
        renderer.write_text(cfg.var_panel_x + 10, cfg.panel_top - 25, ' Variables', cfg.font_bold, cfg.accent)
        info = f'Step {step_idx}/{total_steps}  |  {event}  |  {func_name}'
        renderer.write_text(cfg.var_panel_x + 10, cfg.panel_top - 50, info, ('Consolas', 9, 'normal'), cfg.line_num_color)
        if return_value is not None and event in ('return', 'exception'):
            renderer.write_text(cfg.var_panel_x + 10, cfg.panel_top - 75, f'return: {return_value!r}', cfg.font_bold, cfg.val_color)
        y = cfg.var_start_y
        line_h = cfg.var_line_h
        for key, val in vars_dict.items():
            if key == 'self':
                continue
            if y < -360:
                renderer.write_text(cfg.var_panel_x + 10, y, '... (truncated)', cfg.font, cfg.line_num_color)
                break
            renderer.write_text(cfg.var_key_x, y - line_h + 14, f'{key} =', cfg.font, cfg.key_color)
            val_str = repr(val)
            if len(val_str) > cfg.var_max_val_len:
                val_str = val_str[:cfg.var_max_val_len - 3] + '...'
            renderer.write_text(cfg.var_val_x, y - line_h + 14, val_str, cfg.font, cfg.val_color)
            y -= line_h

class SummaryPanel(Panel):
    """Renders final test results summary."""

    def draw(self, renderer: TurtleRenderer, steps: list[dict]) -> None:
        cfg = self._config
        bg_h = cfg.panel_height + cfg.panel_top - cfg.header_y
        renderer.draw_rect(cfg.code_panel_x, cfg.header_y, cfg.header_width, bg_h, cfg.bg)
        total = len(steps)
        passed = sum(1 for tc in steps if tc.get('return_value') == tc.get('expected') and tc.get('expected') is not None)
        color = cfg.val_color if passed == total else cfg.fail_color
        renderer.write_text(0, cfg.panel_top - 30, f'  {passed}/{total} tests passed', ('Consolas', 16, 'bold'), color, 'center')
        y = cfg.panel_top - 80
        for i, tc_data in enumerate(steps):
            rv = tc_data.get('return_value')
            exp = tc_data.get('expected')
            if rv == exp:
                status = 'PASS'
                color = cfg.val_color
            elif exp is not None:
                status = 'FAIL'
                color = cfg.fail_color
            else:
                status = '?'
                color = cfg.line_num_color
            renderer.write_text(-400, y, f'  Test Case {i + 1}:  return {rv!r}  expected {exp!r}  {status}', cfg.font, color)
            y -= cfg.code_line_h + 4
        renderer.write_text(0, -100, 'Click to exit', cfg.font, cfg.line_num_color, 'center')

class Animation:
    """Orchestrates the full animation sequence."""

    def __init__(self, config: AnimationConfig | None=None) -> None:
        self._config = config or AnimationConfig()
        self._renderer = TurtleRenderer(self._config)
        self._code_panel = CodePanel(self._config)
        self._vars_panel = VariablesPanel(self._config)
        self._summary_panel = SummaryPanel(self._config)

    def run(self, source_lines: list[str], steps: list[dict]) -> None:
        self._render_header()
        frames = self._build_frames(steps)
        self._render_frames(frames, source_lines, steps)
        self._renderer.update()
        self._renderer.exit_on_click()

    def _render_header(self) -> None:
        cfg = self._config
        self._renderer.draw_rect(cfg.code_panel_x, cfg.header_y, cfg.header_width, cfg.header_height, cfg.bg)
        self._renderer.write_text(cfg.code_panel_x + 10, cfg.header_y + 12, ' slough  --  Dry-Run Animation', cfg.font_bold, cfg.accent)

    @staticmethod
    def _build_frames(steps: list[dict]) -> list[tuple[int, dict]]:
        frames: list[tuple[int, dict]] = []
        for tc_idx, tc_data in enumerate(steps):
            for step in tc_data.get('steps', []):
                frames.append((tc_idx, step))
            final = tc_data['steps'][-1] if tc_data.get('steps') else {}
            frames.append((tc_idx, {'lineno': final.get('lineno', 0), 'event': 'test_complete', 'func_name': '', 'vars': {}, 'return_value': tc_data.get('return_value')}))
        return frames

    def _render_frames(self, frames: list[tuple[int, dict]], source_lines: list[str], steps: list[dict]) -> None:
        cfg = self._config
        total = len(frames)
        total_tcs = len(steps)
        for i, (tc_idx, step) in enumerate(frames):
            is_complete = step['event'] == 'test_complete'
            self._code_panel.draw(self._renderer, source_lines, None if is_complete else step.get('lineno'))
            self._vars_panel.draw(self._renderer, step.get('vars', {}), i + 1, total, step.get('event', ''), step.get('func_name', ''), step.get('return_value'))
            self._renderer.write_text(cfg.code_panel_x + 10, -390, f'Test case {tc_idx + 1} of {total_tcs}', cfg.font_small, cfg.line_num_color)
            if is_complete:
                rv = step.get('return_value')
                expected = steps[tc_idx].get('expected')
                line = f'Return: {rv!r}'
                if expected is not None:
                    line += '  PASS' if rv == expected else f'  FAIL  (expected: {expected!r})'
                color = cfg.val_color if rv == expected else cfg.fail_color
                self._renderer.write_text(cfg.var_panel_x + 10, -390, line, cfg.font_bold, color)
            self._renderer.update()
            time.sleep(cfg.delay)
        self._summary_panel.draw(self._renderer, steps)
        self._renderer.update()
